INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('a1b687cbdc95c4429096eea4b57953e3272b26a392c7fed9bce1232a212240e0','Viva Voce','Unknown Subject (CH24102)','CH24102','1','2026','Q.1(a)','In the gravimetric estimation of Nickel, why must the addition of alcoholic dimethylglyoxime (DMG) be limited to only a slight excess rather than a large surplus?','\\text{In the gravimetric estimation of Nickel, why must the addition of alcoholic dimethylglyoxime (DMG) be limited to only a slight excess rather than a large surplus?}','Dimethylglyoxime (DMG) is only slightly soluble in water. When an alcoholic solution of DMG is added to an aqueous solution containing nickel ions, the nickel-DMG complex precipitates. If a large excess of alcoholic DMG is added, the DMG itself may precipitate out of the solution because its solubility in the aqueous medium is exceeded. This precipitated DMG would contaminate the nickel-DMG complex precipitate, leading to a positive error in the gravimetric analysis. Therefore, only a slight excess is added to ensure complete precipitation of nickel while keeping the DMG in solution.','\\text{1. Dimethylglyoxime (DMG) is poorly soluble in water, but soluble in alcohol.} \\\\ \\text{2. During the precipitation of Ni(DMG)}_2 \\text{, adding a large excess of alcoholic DMG causes the DMG to exceed its solubility limit in the aqueous mixture.} \\\\ \\text{3. The excess DMG precipitates as a solid, contaminating the Ni(DMG)}_2 \\text{ precipitate.} \\\\ \\text{4. This causes an increase in the measured mass, leading to a positive analytical error.} \\\\ \\text{5. Therefore, a slight excess is added to ensure quantitative recovery of Ni}^{2+} \\text{ while preventing co-precipitation of the reagent.}','To prevent the co-precipitation of excess DMG, which would lead to a positive error in the measured mass of the Ni-DMG complex.','["Gravimetric Estimation", "Nickel DMG"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('de123eaab0848138b78c040c7493f2ecda6ec052e04f2c41326a99d288850723','Viva Voce','Unknown Subject (CH24102)','CH24102','1','2026','Q.1(b)','Why is the chemical solution initially heated to 70–80 degrees Celsius before completing precipitation during the gravimetric analysis of Nickel?','\\text{Why is the chemical solution initially heated to 70–80 degrees Celsius before completing precipitation during the gravimetric analysis of Nickel?}','1. Conceptual Analysis: The gravimetric determination of Nickel involves precipitation with dimethylglyoxime (DMG). The process requires high purity and large crystal size to facilitate filtration and minimize surface adsorption of impurities. 2. Working: Heating the solution to 70-80 degrees Celsius serves three critical roles. First, it increases the solubility of the nickel-DMG complex temporarily, preventing rapid, disordered precipitation (nucleation) and favoring slow crystal growth (digestion). Second, it reduces the viscosity of the solution, enhancing ion diffusion and allowing for the formation of larger, more perfect crystals. Third, it ensures that the DMG reagent (which is often dissolved in ethanol) is properly integrated into the aqueous matrix before precipitation begins, preventing localized supersaturation. 3. Interpretation: Heating leads to the formation of a coarse, crystalline precipitate that is easier to filter and has a lower surface area-to-volume ratio, significantly reducing the contamination of the final gravimetric precipitate.','\\text{The precipitation of nickel with dimethylglyoxime (DMG) is governed by the principles of crystal growth and solubility. Heating the solution to 70–80 } ^\\circ \\text{C serves the following functions: } \\\\ 1. \\text{ Solubility Control: Higher temperatures increase the solubility of the Ni(DMG)}_2 \\text{ complex, which prevents immediate rapid nucleation. This allows the system to reach the optimal degree of supersaturation required for the growth of large, well-defined crystals.} \\\\ 2. \\text{ Crystal Digestion: By promoting a slower rate of crystal formation, the process minimizes the entrapment of impurities within the crystal lattice (occlusion) and reduces surface adsorption.} \\\\ 3. \\text{ Filtration Efficiency: The resulting coarse crystalline particles are easier to filter and wash compared to fine, colloidal precipitates that would otherwise clog filter paper or sintered glass crucibles.}','Heating promotes the formation of large, pure, and easily filterable crystals by controlling the rate of nucleation and crystal growth.','["Gravimetric Estimation", "Nucleation"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('c78b1ace84504e54fe2da9517f7ef2e6d3faf45afad4521a9f7503ca5dbcfd73','Viva Voce','Unknown Subject (CH24102)','CH24102','2','2026','Q.2(a)','In the complexometric estimation of Calcium and Magnesium ions, why is a specific buffer used to keep the system exactly at pH 10?','\\text{In the complexometric estimation of Calcium and Magnesium ions, why is a specific buffer used to keep the system exactly at pH 10?}','1. Eriochrome Black T (EBT) is the indicator used for determining the combined concentration of calcium and magnesium. It acts as a weak acid that changes color depending on its protonation state. 2. At pH 10, EBT is in its HIn2- form, which exhibits a blue color in the free state and forms a wine-red complex with metal ions (Mg2+). 3. If the pH is too low (acidic), the indicator remains protonated as H2In-, masking the endpoint. 4. If the pH is too high (> 12), Mg2+ ions precipitate as magnesium hydroxide, Mg(OH)2, removing them from the reaction with EDTA. 5. Therefore, a pH of 10 provides the optimal balance to ensure the indicator-metal complex is stable and the EDTA-metal chelation is thermodynamically favored over the metal-hydroxide formation.','The complexometric titration of Ca^{2+} and Mg^{2+} using Eriochrome Black T (EBT) requires a pH of 10 for the following reasons: 1. Indicator Functionality: The color change of EBT is pH-dependent. The metal-indicator complex [MgIn]^- is wine-red and the free indicator HIn^{2-} is blue. The transition occurs optimally near pH 10. 2. Stability of EDTA Complexes: EDTA (Y^{4-}) effectively chelates Ca^{2+} and Mg^{2+} at basic pH. 3. Prevention of Precipitation: At pH > 12, Mg^{2+} precipitates as Mg(OH)_2, which is inert to EDTA titration. 4. Acid-Base Equilibria: At pH < 8, the indicator exists primarily as H_2In^-, which does not show the sharp color transition required for accurate endpoint detection. Thus, maintaining pH 10 ensures the formation of stable [MY]^{2-} complexes and sharp color change.','pH 10 optimizes indicator color transition and prevents Mg(OH)2 precipitation while ensuring EDTA chelation stability.','["Complexometric Titration", "EDTA"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('40f7f1f189565adfaf0b3ecd51e0d687793a51c97d4955f36b49641ed77ae21c','Viva Voce','Unknown Subject (CH24102)','CH24102','2','2026','Q.2(b)','How does the addition of a strongly alkaline medium isolate Calcium ions exclusively from Magnesium ions prior to the second titration step?','\\text{How does the addition of a strongly alkaline medium isolate Calcium ions exclusively from Magnesium ions prior to the second titration step?}','1. Conceptual Analysis: The separation is based on the difference in solubility products (Ksp) of the metal hydroxides. By increasing the pH to approximately 12-13, the concentration of hydroxide ions ([OH-]) becomes sufficiently high to exceed the Ksp of Magnesium hydroxide while leaving Calcium ions in solution. 2. Mechanism: Upon adding a strong base like NaOH, the reaction Mg^2+ + 2OH- -> Mg(OH)2(s) occurs as the ion product [Mg^2+][OH-]^2 exceeds Ksp(Mg(OH)2) ≈ 1.8 x 10^-11. Calcium hydroxide, Ca(OH)2, has a much higher Ksp (≈ 5.5 x 10^-6), meaning it remains soluble at this pH. 3. Result: Magnesium is precipitated as solid Mg(OH)2, effectively masking it from the EDTA titration, allowing for the selective titration of Ca^2+ ions using an indicator like murexide that functions only in highly alkaline conditions.','\\text{1. At pH } \\approx 12-13, \\text{ the [OH}^-\\text{] is approximately } 0.1-1.0 \\text{ M. The solubility product constants are: } K_{sp}(\\text{Mg(OH)}_2) \\approx 1.8 \\times 10^{-11} \\text{ and } K_{sp}(\\text{Ca(OH)}_2) \\approx 5.5 \\times 10^{-6}. \\text{ 2. The precipitation of magnesium occurs when } [\\text{Mg}^{2+}][\\text{OH}^-]^2 > K_{sp}(\\text{Mg(OH)}_2). \\text{ At high pH, this condition is satisfied for Mg}^{2+}, \\text{ forming a precipitate.} \\text{ 3. Since } K_{sp}(\\text{Ca(OH)}_2) \\text{ is much larger, the [OH}^-] \\text{ is insufficient to precipitate calcium, keeping it in the aqueous phase for titration with EDTA.}','\\text{Mg(OH)}_2 \\text{ precipitates due to low } K_{sp} \\text{ at high pH, while Ca}^{2+} \\text{ remains soluble.}','["Complexometric Titration", "Masking Magnesium"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('c73eac939963c12f8822ca0d094c3117e9ff41012a0df20db090f00063d67a77','Viva Voce','Unknown Subject (CH24102)','CH24102','3','2026','Q.3(a)','Why is a specific complementary color wavelength choice required when setting up a colorimeter to verify Beer\'s Law for Iron(III) solutions?','\\text{Why is a specific complementary color wavelength choice required when setting up a colorimeter to verify Beer\'s Law for Iron(III) solutions?}','1. Beer\'s Law states that absorbance is directly proportional to concentration (A = εbc). 2. To maximize sensitivity, the colorimeter must be set to the wavelength of maximum absorbance (λmax) for the analyte. 3. For Iron(III) complexes (e.g., [Fe(SCN)]2+), the solution appears red because it absorbs light in the blue-green region of the visible spectrum. 4. Selecting the complementary color (blue-green, roughly 450-520 nm) ensures that the analyte strongly absorbs the incident light. 5. If the chosen wavelength corresponds to low absorbance, the change in absorbance with respect to concentration becomes negligible, leading to poor signal-to-noise ratios and deviations from Beer\'s Law due to stray light and instrumental limitations.','1. \\text{Beer\'s Law is defined by } A = \\epsilon bc, \\text{ where } \\epsilon \\text{ is the molar absorptivity.} \\newline 2. \\text{To achieve maximum sensitivity, one must select the wavelength } \\lambda_{\\text{max}} \\text{ where } \\epsilon \\text{ is highest.} \\newline 3. \\text{The Fe(III) complex absorbs light in the blue-green region (approx. 450-520 nm) because it exhibits a complementary red color to the human eye.} \\newline 4. \\text{Using } \\lambda_{\\text{max}} \\text{ minimizes relative error and maximizes the slope of the calibration curve, adhering to the requirement for precise quantitative measurement.} \\newline 5. \\text{Operating away from } \\lambda_{\\text{max}} \\text{ leads to a plateauing of the absorbance signal and sensitivity loss, violating the fundamental assumptions required for linear regression analysis in verifying Beer\'s Law.}','Selecting the wavelength of maximum absorbance (λmax), which is complementary to the perceived color of the solution, maximizes sensitivity and ensures a linear relationship between absorbance and concentration.','["Beer\'s Law", "Spectrophotometry"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('a1c25fefe1ffe8e4ae946fd8fc05294b329a512ddbfdc188c4e473fa4a3e79a3','Viva Voce','Unknown Subject (CH24102)','CH24102','3','2026','Q.3(b)','What structural issue or chemical limitation causes the calibration curve of Absorbance versus Concentration to deviate from linearity at high sample concentrations?','\\text{What structural issue or chemical limitation causes the calibration curve of Absorbance versus Concentration to deviate from linearity at high sample concentrations?}','The Beer-Lambert law, A = εbc, assumes that analyte molecules absorb light independently of one another. At high concentrations, the average distance between solute molecules decreases, which leads to electrostatic interactions between them. These interactions modify the charge distribution and electronic energy levels of the analyte molecules, thereby altering their molar absorptivity (ε). Furthermore, high concentrations can change the refractive index of the solution, which may deviate from the conditions under which the instrument was calibrated. Consequently, the linear relationship between absorbance and concentration fails because ε is no longer a constant.','The Beer-Lambert law is derived under the assumption of dilute solutions where particles act independently. Deviations occur at high concentrations due to: 1. Electrostatic interactions: As concentration c increases, the proximity of molecules causes shifts in electronic energy levels, altering the molar absorptivity ε(c). 2. Refractive index effects: The refractive index n of the medium may change significantly with concentration, affecting the effective absorption cross-section as A \\propto \\frac{n}{(n^2+2)^2}. Thus, for c > 0.01 M, the assumption of constant ε fails, leading to non-linearity where A(c) = \\epsilon(c)bc.','Intermolecular electrostatic interactions and changes in the solution\'s refractive index.','["Beer-Lambert Deviations", "Colorimetry"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('a5eddda9c57b8c06a4cd6de13112309370c2b51db67413d7239c6551c236cf40','Viva Voce','Unknown Subject (CH24102)','CH24102','4','2026','Q.4(a)','In liquid-liquid extraction of a binary organic mixture, what is the purpose of converting one of the neutral components into an ionic salt form?','\\text{In liquid-liquid extraction of a binary organic mixture, what is the purpose of converting one of the neutral components into an ionic salt form?}','1. Understand the principle of liquid-liquid extraction: Separation is based on the partition coefficient (distribution ratio) between two immiscible phases, typically an organic solvent and an aqueous solvent. 2. Recognize solubility differences: Neutral organic compounds are generally non-polar or weakly polar and have high solubility in organic solvents but low solubility in aqueous phases. 3. Mechanism of ionization: By adding an acid or base, a neutral component containing an acidic or basic functional group can be converted into its conjugate ionic salt form (e.g., a carboxylic acid becomes a carboxylate, or an amine becomes an ammonium salt). 4. Effect on solubility: Ionic salts are highly polar and hydrated by water molecules, drastically increasing their solubility in the aqueous phase compared to the organic phase. 5. Conclusion: This conversion creates a large partition coefficient difference between the neutral species (staying in the organic layer) and the ionic species (moving into the aqueous layer), allowing for the physical separation of the two components by decantation.','\\text{Step 1: Identify that liquid-liquid extraction relies on the differential solubility of components between an organic phase and an aqueous phase.} \\\\ \\text{Step 2: Note that neutral organic molecules possess low aqueous solubility due to their non-polar character.} \\\\ \\text{Step 3: Recognize that converting a component into an ionic salt significantly increases its polarity and hydrogen-bonding potential.} \\\\ \\text{Step 4: Conclude that the salt becomes preferentially soluble in the aqueous phase, effectively separating it from the remaining neutral organic component in the organic phase, based on the partition coefficient shift: } K_D = \\frac{[C]_{\\text{org}}}{[C]_{\\text{aq}}} \\ll 1 \\text{ for the salt species.}','To increase the solubility of a specific component in the aqueous phase by ionizing it, thereby facilitating its separation from the neutral component remaining in the organic phase.','["Acid-Base Extraction", "Organic Separation"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('4ad010db561e93c6fb03ba68ed0eb71e56fdb5d9270ba064287079ceffdb1e32','Viva Voce','Unknown Subject (CH24102)','CH24102','4','2026','Q.4(b)','Which diagnostic absorption bands in an FTIR spectrum quickly differentiate a terminal carboxylic acid component from a basic amine inside an isolated organic layer?','\\text{Which diagnostic absorption bands in an FTIR spectrum quickly differentiate a terminal carboxylic acid component from a basic amine inside an isolated organic layer?}','1. Conceptual Analysis: Carboxylic acids and amines possess distinct functional group vibrations. A carboxylic acid is characterized by a strong, broad O-H stretch and a characteristic C=O carbonyl stretch. Conversely, a primary or secondary amine is identified by N-H stretching vibrations and the absence of a strong carbonyl signal. \n2. Step-by-Step Differentiation: \n- Carboxylic Acid: Look for the \'broad-base\' O-H stretch spanning 2500–3300 cm⁻¹ that often obscures the C-H region, coupled with a strong C=O stretch near 1700–1725 cm⁻¹. \n- Basic Amine: Look for N-H stretching vibrations in the 3300–3500 cm⁻¹ range. Primary amines show two distinct bands (symmetric/asymmetric), while secondary amines show one. \n- Key contrast: The carboxylic acid O-H is much broader and shifted to lower wavenumbers than the N-H stretch, and the intense carbonyl peak is diagnostic for the acid, whereas amines lack this feature in the 1700 cm⁻¹ region. \n3. Interpretation: By identifying the presence of the carbonyl peak (1700 cm⁻¹) and the extremely broad O-H hydroxyl stretch, one confirms a carboxylic acid, whereas N-H stretches at higher wavenumbers without a C=O peak confirm an amine.','\\text{1. Analysis: Carboxylic acids exhibit a characteristic strong carbonyl (C=O) stretch at } \\approx 1710 \\text{ cm}^{-1} \\text{ and a broad O-H stretch extending from } 2500\\text{--}3300 \\text{ cm}^{-1}. \\text{ Amines (R-NH}_2\\text{ or R}_2\\text{NH) exhibit N-H stretching vibrations in the } 3300\\text{--}3500 \\text{ cm}^{-1} \\text{ region and lack a carbonyl signal.} \\\\ \\text{2. Differentiation: The presence of the } \\text{C=O} \\text{ band (1700 cm}^{-1}\\text{) serves as the primary diagnostic differentiator. The broad, low-wavenumber O-H stretch of the acid contrasts with the sharper, higher-wavenumber N-H stretches of the amine.} \\\\ \\text{3. Interpretation: A terminal carboxylic acid is identified by the concurrent signals of C=O (strong, 1710 cm}^{-1}\\text{) and the broad O-H (2500--3300 cm}^{-1}\\text{). A basic amine is identified by N-H stretches (3300--3500 cm}^{-1}\\text{) and the absence of the } 1700 \\text{ cm}^{-1} \\text{ C=O band.}','Carboxylic acid: C=O stretch (1700–1725 cm⁻¹) and broad O-H stretch (2500–3300 cm⁻¹). Amine: N-H stretches (3300–3500 cm⁻¹), lacking the C=O stretch.','["FTIR Characterization", "Spectroscopy"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('4544aa5ac95a849b7c7b58a94e32e9a42aadb3e1f3bc378c0c4e58003f76917e','Viva Voce','Unknown Subject (CH24102)','CH24102','5','2026','Q.5(a)','Why must the preparation of Diazoaminobenzene be strictly maintained below 5 degrees Celsius during the initial diazotization step?','\\text{Why must the preparation of Diazoaminobenzene be strictly maintained below 5 degrees Celsius during the initial diazotization step?}','1. The initial step of the synthesis involves the reaction of aniline with nitrous acid (generated in situ from sodium nitrite and HCl) to form the benzenediazonium ion. 2. Benzenediazonium salts are highly unstable and thermally sensitive; at temperatures above 5 degrees Celsius, they undergo rapid thermal decomposition into phenol and nitrogen gas. 3. Maintaining the temperature below 5 degrees Celsius suppresses this decomposition pathway, ensuring a sufficient concentration of the diazonium intermediate for the subsequent coupling reaction with excess aniline to form diazoaminobenzene. 4. Furthermore, elevated temperatures promote side reactions and hydrolysis, which would drastically reduce the yield and purity of the final product.','1. \\text{Formation of the benzenediazonium ion: } C_6H_5NH_2 + HNO_2 + HCl \\rightarrow [C_6H_5N_2]^+Cl^- + 2H_2O. 2. \\text{Thermal instability of diazonium salts: } [C_6H_5N_2]^+Cl^- + H_2O \\rightarrow C_6H_5OH + N_2(g) + HCl. 3. \\text{Low temperatures are critical to prevent the nucleophilic attack of water and the evolution of } N_2. 4. \\text{Maintaining } T < 5 ^\\circ C \\text{ ensures the stability of the intermediate for the subsequent coupling reaction: } [C_6H_5N_2]^+Cl^- + C_6H_5NH_2 \\rightarrow C_6H_5-N=N-NH-C_6H_5 + HCl.','To prevent the thermal decomposition of the unstable benzenediazonium intermediate into phenol and nitrogen gas.','["Diazotization", "Organic Synthesis"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('129419a370268663c402f2f7d4dd544c55379850afa05a08ac8ab89be674f54b','Viva Voce','Unknown Subject (CH24102)','CH24102','5','2026','Q.5(b)','What structural change or impurity feature during synthesis causes an isolated Diazoaminobenzene sample to show a broad melting point range rather than a sharp single value?','\\text{What structural change or impurity feature during synthesis causes an isolated Diazoaminobenzene sample to show a broad melting point range rather than a sharp single value?}','1. Conceptual Analysis: The synthesis of diazoaminobenzene typically involves the coupling of benzenediazonium chloride with aniline. The reaction is pH-sensitive and can lead to side products, specifically the aminoazobenzene rearrangement product or unreacted starting materials. A broad melting point indicates a mixture of substances rather than a pure crystalline lattice. 2. Working: Impurities such as 4-aminoazobenzene, formed by acid-catalyzed rearrangement of diazoaminobenzene, act as solutes in the diazoaminobenzene solvent. According to the laws of freezing point depression/melting point depression, the presence of impurities disrupts the crystal lattice, leading to a depression in the melting point and a broadened range as the composition of the liquid phase changes during the melting process. 3. Interpretation: The broad range is primarily due to the presence of 4-aminoazobenzene and residual aniline, which lowers the chemical potential of the solid phase and necessitates a wider temperature interval for the transition from solid to liquid.','\\text{Step 1: The synthesis involves the coupling reaction: } C_6H_5N_2Cl + C_6H_5NH_2 \\rightarrow C_6H_5N=NNHC_6H_5 + HCl. \\text{ Step 2: The acid-catalyzed rearrangement leads to the formation of 4-aminoazobenzene: } C_6H_5N=NNHC_6H_5 \\xrightarrow{H^+} C_6H_5N=NC_6H_4NH_2. \\text{ Step 3: According to the colligative property of melting point depression, the presence of 4-aminoazobenzene impurity decreases the solid-liquid equilibrium temperature of the mixture: } \\Delta T_f = K_f \\cdot m. \\text{ Step 4: Because the impurity concentration changes as the mixture melts, the melting occurs over a range of temperatures rather than a single point.}','Presence of 4-aminoazobenzene impurity via acid-catalyzed rearrangement.','["Melting Point Analysis", "Organic Synthesis"]','analytical','0.95',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('b994fd9862dff5285fd09fbb49ccb267c6efa6a8e8ae064580751441806165a0','Viva Voce','Unknown Subject (CH24102)','CH24102','6','2026','Q.6(a)','What is the thermodynamic definitions of a \'Eutectic Point\' on a solid-liquid binary phase diagram?','\\text{What is the thermodynamic definitions of a \'Eutectic Point\' on a solid-liquid binary phase diagram?}','1. Consider a binary system with components A and B at constant pressure. The Gibbs Phase Rule is F = C - P + 1 (since pressure is fixed). 2. At the eutectic point, three phases coexist in equilibrium: the liquid phase (L) and two distinct solid phases (alpha and beta). 3. Setting C = 2 (binary system) and P = 3 (three phases), we get F = 2 - 3 + 1 = 0. 4. This indicates that the system is invariant, meaning the temperature and composition of the liquid are fixed at this point. 5. Thermodynamically, the eutectic point is the state where the chemical potentials of both components are equal across all three phases: mu_A(L) = mu_A(alpha) = mu_A(beta) and mu_B(L) = mu_B(alpha) = mu_B(beta).','For a binary system at constant pressure, the Gibbs phase rule is given by F = C - P + 1. At the eutectic point, three phases coexist in equilibrium: one liquid phase (L) and two solid phases (\\alpha and \\beta), implying P = 3. Substituting C = 2 (for a binary system) and P = 3 into the phase rule: F = 2 - 3 + 1 = 0. An invariant point (F=0) indicates that the temperature (T) and the composition (x) are uniquely determined. Thermodynamically, this equilibrium is defined by the equality of chemical potentials for all components i in all phases \\phi: \\mu_i^L = \\mu_i^\\alpha = \\mu_i^\\beta \\text{ for } i \\in \\{A, B\\}.','An invariant state (F=0) where the liquid phase and two solid phases coexist in chemical equilibrium: \\mu_i^L = \\mu_i^\\alpha = \\mu_i^\\beta.','["Engineering Thermodynamics", "Eutectic Mixture", "Phase Equilibria"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('54ea7a0298f78c6cd2ee45c456cea8d0c7f8270377d48a0ef20530bb69e99479','Viva Voce','Unknown Subject (CH24102)','CH24102','6','2026','Q.6(b)','According to Gibbs Phase Rule, how many degrees of freedom exist exactly at the eutectic temperature for a two-component condensed system at constant atmospheric pressure?','\\text{According to Gibbs Phase Rule, how many degrees of freedom exist exactly at the eutectic temperature for a two-component condensed system at constant atmospheric pressure?}','1. Understand the Reduced Gibbs Phase Rule for condensed systems: When pressure is held constant (P = constant), the Gibbs Phase Rule F = C - P + 2 simplifies to the condensed phase rule: F\' = C - P + 1. 2. Identify the variables: Here, C = 2 (two-component system). 3. Identify the phase state at the eutectic temperature: At the eutectic temperature, three phases coexist in equilibrium: the liquid phase and two solid phases (solid A and solid B). Thus, P = 3. 4. Calculate: F\' = 2 - 3 + 1 = 0. 5. Interpretation: A result of 0 means the system is invariant, meaning the eutectic point occurs at a fixed temperature and composition for a given pressure.','The reduced Gibbs Phase Rule for a condensed system at constant pressure is given by F\' = C - P + 1, where F\' is the number of degrees of freedom, C is the number of components, and P is the number of phases at equilibrium. Given C = 2 components and at the eutectic temperature, there exist 3 phases (Liquid, Solid A, and Solid B), so P = 3. Substituting these values: F\' = 2 - 3 + 1 = 0. An invariant point (F\'=0) indicates that the eutectic temperature and composition are fixed for a specific pressure.','0','["Phase Equilibria", "Phase Rule", "Thermodynamics"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('0050af3786481d027e18d6290dad25b61ca97e4585ddf430784d4f6ab54e9976','Viva Voce','Unknown Subject (CH24102)','CH24102','7','2026','Q.7(a)','Why is the acid-catalyzed hydrolysis of ethyl acetate classified as a pseudo-first-order reaction rather than a true second-order kinetic process?','\\text{Why is the acid-catalyzed hydrolysis of ethyl acetate classified as a pseudo-first-order reaction rather than a true second-order kinetic process?}','1. The hydrolysis of ethyl acetate is represented by the reaction: CH3COOCH2CH3 + H2O -> CH3COOH + CH3CH2OH. 2. The rate law is theoretically second-order: Rate = k[CH3COOCH2CH3][H2O]. 3. In acid-catalyzed hydrolysis, water is used as the solvent and is present in such a large excess that its concentration remains effectively constant during the reaction ([H2O] is approximately constant). 4. We can define a new pseudo-rate constant k\' = k[H2O]. 5. The rate law simplifies to Rate = k\'[CH3COOCH2CH3], which is mathematically first-order, hence it is termed pseudo-first-order.','\\text{The reaction is: } CH_3COOCH_2CH_3 + H_2O \\xrightarrow{H^+} CH_3COOH + CH_3CH_2OH. \\\\ \\text{The theoretical rate law is: } Rate = k[CH_3COOCH_2CH_3][H_2O]. \\\\ \\text{Since } H_2O \\text{ is the solvent, its concentration } [H_2O] \\text{ remains nearly constant throughout the reaction.} \\\\ \\text{Let } k\' = k[H_2O] \\approx \\text{constant.} \\\\ \\text{Then, the rate law becomes: } Rate = k\'[CH_3COOCH_2CH_3]. \\\\ \\text{This follows first-order kinetics with respect to ethyl acetate, thus it is a pseudo-first-order reaction.}','The reaction is classified as pseudo-first-order because water is in large excess, making its concentration effectively constant and constant-like, simplifying the second-order rate law to one dependent only on the ethyl acetate concentration.','["Chemical Kinetics", "Pseudo-First-Order"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('f2867d7bc985fa8feae7139b0bd018b395926db6ee579b19732f71cad052081f','Viva Voce','Unknown Subject (CH24102)','CH24102','7','2026','Q.7(b)','What role does the concentration of the mineral acid catalyst play in determining the absolute reaction rate constant during ester hydrolysis?','\\text{What role does the concentration of the mineral acid catalyst play in determining the absolute reaction rate constant during ester hydrolysis?}','1. Conceptual Analysis: Acid-catalyzed ester hydrolysis follows a mechanism where the rate-determining step involves the attack of water on the protonated ester. The mineral acid (H+) serves as a catalyst, and the rate law is typically given by Rate = k[Ester][H2O][H+]. 2. Working: The observed rate constant, k_obs, is defined such that Rate = k_obs[Ester]. Since the water concentration is effectively constant in aqueous solutions, the relationship is k_obs = k_true[H2O][H+]. Here, k_true is the absolute reaction rate constant. 3. Interpretation: The concentration of the mineral acid does not change the \'absolute\' rate constant (which is a temperature-dependent kinetic parameter); instead, it modifies the \'observed\' rate constant proportionally. Thus, the absolute rate constant remains independent of [H+].','\\text{The rate of acid-catalyzed ester hydrolysis is given by: } v = k_{true}[Ester][H_2O][H^+]. \\text{ The experimental rate law is: } v = k_{obs}[Ester]. \\text{ Thus, } k_{obs} = k_{true}[H_2O][H^+]. \\text{ Since } k_{true} \\text{ is a fundamental kinetic constant dependent only on temperature (Arrhenius equation), it is independent of the catalyst concentration. The acid concentration [H}^+] \\text{ scales the observed rate } k_{obs} \\text{ but does not determine the absolute rate constant } k_{true}.','The absolute reaction rate constant (k_true) is independent of the catalyst concentration; the catalyst concentration only determines the observed rate constant (k_obs).','["Acid Catalysis", "Chemical Kinetics"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('92513dd596d29a4874cc7032ad6d67ba2c4f654f6e2addc535ee0913c5c47d8b','Viva Voce','Unknown Subject (CH24102)','CH24102','8','2026','Q.8(a)','In studying the kinetics of the iodide-hydrogen peroxide clock reaction, what physical property is evaluated to monitor the sudden endpoint of the initial reaction step?','\\text{In studying the kinetics of the iodide-hydrogen peroxide clock reaction, what physical property is evaluated to monitor the sudden endpoint of the initial reaction step?}','1. Identify the reaction components: The iodide-hydrogen peroxide clock reaction typically involves iodide ions, hydrogen peroxide, and a starch indicator in the presence of a limiting amount of thiosulfate ions.\n2. Explain the mechanism: Initially, iodide is oxidized to iodine by hydrogen peroxide. The thiosulfate reacts instantly with the iodine produced to regenerate iodide, preventing the accumulation of iodine.\n3. Determine the indicator role: Once the thiosulfate is entirely consumed, any further iodine produced by the oxidation reaction reacts with the starch indicator.\n4. Identify the physical property: The reaction endpoint is marked by the sudden appearance of a deep blue (or blue-black) complex, which is a physical manifestation of light absorption changes due to the triiodide-starch complex formation.','The kinetics of the iodide-hydrogen peroxide clock reaction are studied by monitoring the induction time before the visual color change occurs. The mechanism follows these steps:\n1. Oxidation of iodide: H_2O_2 + 2I^- + 2H^+ \\rightarrow I_2 + 2H_2O\n2. Consumption of thiosulfate: I_2 + 2S_2O_3^{2-} \\rightarrow 2I^- + S_4O_6^{2-}\n3. Endpoint indicator: Once S_2O_3^{2-} is depleted, I_2 reacts with starch to form the blue complex: I_2 + I^- + \\text{starch} \\rightarrow I_3^-\\text{-starch (blue)}.\nThe physical property evaluated is the optical absorbance (or the visual color) of the triiodide-starch complex.','optical absorbance (visual color change)','["Clock Reaction", "Reaction Dynamics"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('f7fa9b10a9e9259f447338086f06e0cd39ff16c0440e18b7cc44f4870edff989','Viva Voce','Unknown Subject (CH24102)','CH24102','8','2026','Q.8(b)','How does adding a specific chemical catalyst like Fe(III) physically alter the activation energy barrier for the reaction between iodide and peroxide?','\\text{How does adding a specific chemical catalyst like Fe(III) physically alter the activation energy barrier for the reaction between iodide and peroxide?}','1. Conceptual Analysis: Catalysts accelerate reactions by providing an alternative reaction mechanism with a lower activation energy (Ea) compared to the uncatalyzed path. For the reaction between iodide (I-) and peroxide (H2O2), Fe(III) acts as a homogeneous catalyst by forming intermediate complexes that facilitate electron transfer, effectively partitioning the overall reaction into elementary steps with lower individual energy barriers.\n\n2. Working: The uncatalyzed reaction is kinetically slow due to a high collision energy requirement for the direct oxidation-reduction. By adding Fe(III), the mechanism shifts to:\nStep 1: 2Fe(III) + 2I- -> 2Fe(II) + I2\nStep 2: 2Fe(II) + H2O2 + 2H+ -> 2Fe(III) + 2H2O\nThese individual steps involve intermediate Fe species which stabilize the transition state, lowering the Gibbs free energy of the activation barrier, delta G double-dagger.\n\n3. Interpretation: The presence of Fe(III) physically alters the reaction landscape by creating an alternative coordinate pathway where the energetic peak of the rate-determining step is significantly lower, leading to an exponential increase in the rate constant according to the Arrhenius equation, k = A * exp(-Ea/RT).','\\text{The uncatalyzed reaction rate constant is defined by } k_u = A_u e^{-\\frac{E_{a,u}}{RT}}. \\text{ The addition of Fe(III) provides an alternative reaction coordinate with a modified transition state. The catalyzed mechanism proceeds via intermediate formation: } \\text{Step 1: } 2Fe^{3+} + 2I^- \\rightarrow 2Fe^{2+} + I_2; \\text{ Step 2: } 2Fe^{2+} + H_2O_2 + 2H^+ \\rightarrow 2Fe^{3+} + 2H_2O. \\text{ Because } E_{a,cat} < E_{a,u}, \\text{ the rate } k_{cat} = A_{cat} e^{-\\frac{E_{a,cat}}{RT}} \\text{ satisfies } k_{cat} \\gg k_u \\text{ at constant temperature } T.','The catalyst lowers the activation energy by providing an alternative mechanism with lower-energy intermediate transition states.','["Catalyst Effect", "Reaction Dynamics"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('27ac67dcd3effb8017808c7938a350449a95dc4bf749416c330a908b0524dc2d','Viva Voce','Unknown Subject (CH24102)','CH24102','9','2026','Q.9(a)','What physical parameter drop or plateau identifies the exact equivalence point during a potentiometric strong acid-strong base titration?','\\text{What physical parameter drop or plateau identifies the exact equivalence point during a potentiometric strong acid-strong base titration?}','1. In a potentiometric titration, the potential (typically measured as pH) is plotted against the volume of titrant added. 2. The equivalence point is defined by the point of maximum slope on the titration curve. 3. Mathematically, the first derivative of the pH with respect to volume (dpH/dV) exhibits a sharp peak (a maximum), while the second derivative (d2pH/dV2) crosses zero at this precise point. 4. Therefore, the parameter identified is the inflection point of the titration curve, characterized by the maximum rate of change in potential.','\\text{1. Define the titration curve as } pH = f(V_{titrant}). \\\\ \\text{2. The equivalence point corresponds to the inflection point of the titration curve.} \\\\ \\text{3. At the inflection point, the first derivative } \\frac{dpH}{dV} \\text{ reaches a maximum value, and the second derivative } \\frac{d^2pH}{dV^2} \\text{ equals zero.} \\\\ \\text{4. The rapid change in potential (steepest slope) identifies the exact equivalence point.}','The inflection point of the titration curve (the maximum of the first derivative of pH with respect to titrant volume).','["Electrochemistry", "Potentiometric Titration"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('fb19f0934434902699ef2a13bd65cb1d240a71b7566994d1a2609c4b28749f9c','Viva Voce','Unknown Subject (CH24102)','CH24102','9','2026','Q.9(b)','Why do potentiometric titrations provide higher analytical precision over traditional indicator color changes when examining turbid or highly colored liquid solutions?','\\text{Why do potentiometric titrations provide higher analytical precision over traditional indicator color changes when examining turbid or highly colored liquid solutions?}','1. Conceptual Analysis: Traditional indicator-based titrations rely on the visual detection of a color change at the equivalence point. In turbid or colored solutions, the analyte\'s natural absorption or scattering of light masks or shifts the perceived color of the indicator, introducing significant systematic error and observer bias. 2. Working: Potentiometric titration measures the potential difference (E) between an indicator electrode (sensitive to analyte concentration) and a reference electrode. The equivalence point is determined mathematically by the inflection point of the titration curve (dE/dV or d2E/dV2). Since this electrochemical measurement is independent of the solution\'s optical properties, it bypasses the interference of turbidity or color. 3. Interpretation: By replacing subjective visual estimation with objective electrochemical data processing, the precision of the equivalence point detection is significantly enhanced, as the inflection point remains detectable regardless of light interference.','\\text{1. Visual limitations: } I_{observed} = I_{indicator} + I_{background} \\implies \\text{Signal-to-noise ratio decreases in colored/turbid media.} \\\\ \\text{2. Potentiometric principle: } E_{cell} = E_{ind} - E_{ref} + E_{j}. \\text{ The equivalence point is defined by } \\frac{d^2E}{dV^2} = 0. \\\\ \\text{3. Conclusion: } \\text{Since } \\frac{d^2E}{dV^2} \\text{ is independent of optical absorbance } (A) \\text{ or scattering } (S), \\text{ potentiometry provides superior accuracy over visual observation in non-transparent media.}','Potentiometric titrations offer superior precision because electrochemical potential measurements are independent of the solution\'s optical properties, unlike visual indicators which are obscured by turbidity or matrix color.','["Complex Analysis", "Electrochemistry", "Titration Precision"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('eedb9665daa606a7e53cb3f96d56ec5df55e4521685a4f97aa22173cc52c929b','Viva Voce','Unknown Subject (CH24102)','CH24102','10','2026','Q.10(a)','What physical event or crystalline transition marks the transition temperature of a salt hydrate compound?','\\text{What physical event or crystalline transition marks the transition temperature of a salt hydrate compound?}','1. A salt hydrate is a crystalline solid containing a specific number of water molecules bound within its crystal lattice. 2. The transition temperature (or incongruent melting point) of a salt hydrate occurs when the hydrate decomposes into its anhydrous salt and a saturated solution of the salt in water. 3. Physically, this represents the point where the solid hydrate becomes unstable in the presence of its own water of crystallization. 4. Thermodynamically, this is the temperature at which the chemical potential of the solid hydrate equals the chemical potential of the mixture of anhydrous salt and saturated solution.','The transition temperature of a salt hydrate, often termed the incongruent melting point, is defined by the equilibrium reaction: \\text{Salt} \\cdot n\\text{H}_2\\text{O} (s) \\rightleftharpoons \\text{Salt} (s) + \\text{Saturated Solution (aq)}. At this temperature, the solid hydrate undergoes a peritectic transformation, where the crystalline structure collapses as the lattice water is released to form a saturated liquid phase while the excess solid salt remains.','Incongruent melting (peritectic transformation)','["Salt Hydrates", "Thermal Analysis"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('cd7effbf9714c614ac3cfeff5e91d8b58936376c07cfb77ec6f49be060683038','Viva Voce','Unknown Subject (CH24102)','CH24102','10','2026','Q.10(b)','Why must the cooling rate of the salt hydrate solution be kept slow and uniform to prevent severe deviations when observing the true crystallization point?','\\text{Why must the cooling rate of the salt hydrate solution be kept slow and uniform to prevent severe deviations when observing the true crystallization point?}','1. Conceptual Analysis: The crystallization point of a salt hydrate solution is defined by the thermal equilibrium between the solid and liquid phases. A rapid cooling rate creates a large temperature gradient between the bulk solution and the container walls, leading to thermal gradients that prevent uniform nucleation. Furthermore, rapid cooling often induces supercooling, where the solution drops below its freezing point without initiating crystal growth, leading to inaccurate measurement of the equilibrium temperature.\n2. Step-by-Step Reasoning: \n   a) Equilibrium Maintenance: Slow cooling ensures that the latent heat of crystallization is dissipated evenly, keeping the system near phase equilibrium.\n   b) Nucleation Control: A slow rate minimizes the degree of supercooling, ensuring that the detected temperature spike (due to exothermic heat of crystallization) corresponds to the true equilibrium temperature rather than an artifact of rapid, non-equilibrium growth.\n   c) Thermal Uniformity: Uniform cooling eliminates local concentration and thermal gradients that would otherwise cause biased reading of the true melting/crystallization point.\n3. Interpretation: Deviations in temperature readings are minimized when the system stays close to the thermodynamic equilibrium path.','\\text{1. Analysis: The crystallization point } T_c \\text{ requires the system to be in phase equilibrium. A cooling rate } \\frac{dT}{dt} \\text{ that is too high leads to } T_{observed} < T_{equilibrium} \\text{ due to supercooling effects.} \\\\ \\text{2. Heat Balance: } Q_{released} = \\Delta H_{crys} \\cdot n_{crys}. \\text{ Rapid cooling prevents the efficient dissipation of } Q_{released}, \\text{ causing thermal gradients within the bulk.} \\\\ \\text{3. Kinetic Control: To ensure } T_{observed} \\approx T_{true}, \\text{ the system must satisfy } \\frac{dT}{dt} \\to 0 \\text{ as } T \\to T_c \\text{ to allow sufficient time for nuclei to form and grow under equilibrium conditions.}','A slow and uniform cooling rate is necessary to minimize supercooling and eliminate thermal gradients, ensuring the observed temperature spike reflects the thermodynamic equilibrium phase transition.','["Supercooling Effects", "Thermal Analysis"]','analytical','0.98',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('610369ebf2b588021e86c4714bdd19d0708235ba618f7b4e06a28082f1445dec','Viva Voce','Unknown Subject (CH24102)','CH24102','11','2026','Q.11(a)','In Lassaigne\'s test for detecting heteroatoms, what is the chemical reason for fusing the organic sample directly with metallic sodium?','\\text{In Lassaigne\'s test for detecting heteroatoms, what is the chemical reason for fusing the organic sample directly with metallic sodium?}','1. Organic compounds typically contain heteroatoms (like N, S, or halogens) covalently bonded to carbon, which are difficult to detect via standard ionic precipitation tests. 2. Metallic sodium acts as a powerful reducing agent. When fused with the organic substance, it breaks these strong covalent bonds. 3. The sodium reacts with the carbon and the heteroatoms to form water-soluble inorganic sodium salts: NaCN (for nitrogen), Na2S (for sulfur), and NaX (for halogens, where X is Cl, Br, or I). 4. These ionic salts dissociate in water, allowing for subsequent identification using standard qualitative inorganic reagents.','1. \\text{Organic molecules contain covalent bonds between carbon and heteroatoms (N, S, X). These bonds are not readily reactive with common aqueous test reagents.} \\\\ 2. \\text{Sodium metal is a strong reducing agent. Heating with Na facilitates the cleavage of these covalent bonds.} \\\\ 3. \\text{The reaction converts covalently bound elements into ionic, water-soluble sodium salts:} \\\\ \\text{Na} + \\text{C} + \\text{N} \\rightarrow \\text{NaCN} \\\\ 2\\text{Na} + \\text{S} \\rightarrow \\text{Na}_2\\text{S} \\\\ \\text{Na} + \\text{X} \\rightarrow \\text{NaX} \\\\ 4. \\text{These ionic products dissolve in the extraction solvent (distilled water), enabling standard qualitative analysis.}','To convert covalently bonded heteroatoms into water-soluble ionic sodium salts (NaCN, Na2S, NaX) for standard qualitative identification.','["Lassaigne\'s Test", "Qualitative Organic Analysis"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('2076c011230155280bdc9e75a57d6e632933bc8949d49b2d4e1c9849ad5bc9aa','Viva Voce','Unknown Subject (CH24102)','CH24102','11','2026','Q.11(b)','Why does a distinctive Prussian Blue coloration appear when testing for Nitrogen in a Lassaigne\'s filtrate sample upon adding freshly prepared iron(II) sulfate?','\\text{Why does a distinctive Prussian Blue coloration appear when testing for Nitrogen in a Lassaigne\'s filtrate sample upon adding freshly prepared iron(II) sulfate?}','Step 1: The Lassaigne\'s test converts organic nitrogen into sodium cyanide (NaCN) by fusing the organic compound with metallic sodium. Step 2: Upon adding freshly prepared iron(II) sulfate (FeSO4) to the filtrate, the cyanide ions react to form hexacyanoferrate(II) ions: Fe2+ + 6CN- -> [Fe(CN)6]4-. Step 3: A portion of the Fe2+ ions is oxidized to Fe3+ by exposure to air. Step 4: The Fe3+ ions then react with the [Fe(CN)6]4- ions to form the complex iron(III) hexacyanoferrate(II), known as Prussian Blue: 4Fe3+ + 3[Fe(CN)6]4- -> Fe4[Fe(CN)6]3. The intense blue color confirms the presence of nitrogen.','1. \\text{Fusion: } Na + C + N \\rightarrow NaCN \\\\ 2. \\text{Complexation: } Fe^{2+} + 6CN^{-} \\rightarrow [Fe(CN)_{6}]^{4-} \\\\ 3. \\text{Oxidation: } Fe^{2+} \\xrightarrow{O_{2}} Fe^{3+} \\\\ 4. \\text{Precipitation: } 4Fe^{3+} + 3[Fe(CN)_{6}]^{4-} \\rightarrow Fe_{4}[Fe(CN)_{6}]_{3} \\text{ (Prussian Blue)}','Fe4[Fe(CN)6]3','["Heteroatom Detection", "Qualitative Organic Analysis"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('94f4da3b48bceb34090a2e766552a1e17068e1798b2e8b6ef636d776fb8e303f','Viva Voce','Unknown Subject (CH24102)','CH24102','12','2026','Q.12(a)','Why does the inflection point on a graph plotting pH versus Volume of titrant added perfectly signify the equivalence point of a neutralization reaction?','\\text{Why does the inflection point on a graph plotting pH versus Volume of titrant added perfectly signify the equivalence point of a neutralization reaction?}','1. In an acid-base titration, the pH is defined as the negative logarithm of the hydronium ion concentration: pH = -log[H3O+]. 2. Near the equivalence point, a small addition of titrant results in a massive change in the concentration of [H3O+] because the solution transitions from being dominated by the analyte to being dominated by the excess titrant. 3. Mathematically, the titration curve is a function pH(V). The inflection point occurs where the second derivative of the curve with respect to volume is zero (d^2pH/dV^2 = 0). 4. In a neutralization reaction involving a strong acid and a strong base, the titration curve is symmetric near the equivalence point. Because the H3O+ concentration changes by several orders of magnitude as the stoichiometric ratio is reached, the slope d(pH)/dV reaches its maximum at exactly the point where the moles of titrant equal the moles of analyte (the equivalence point). Thus, the point of maximum slope (the inflection point) corresponds to the stoichiometric equivalence point.','The pH of a solution is defined as pH = -\\log_{10}[H_3O^+]. The equivalence point is defined as the volume V_eq where n_{acid} = n_{base}. In the region of the equivalence point, the rate of change of pH with respect to the volume of titrant V is given by the derivative \\frac{dpH}{dV}. By the chain rule, \\frac{dpH}{dV} = \\frac{dpH}{d[H_3O^+]} \\cdot \\frac{d[H_3O^+]}{dV}. Since pH = -\\log_{10}[H_3O^+], we have \\frac{dpH}{d[H_3O^+]} = -\\frac{1}{[H_3O^+]\\ln(10)}. As the system approaches the equivalence point, [H_3O^+] approaches a value determined by the auto-ionization of water (1.0 \\times 10^{-7} M). At this precise stoichiometry, the rate of change of concentration with respect to volume is at its local maximum due to the abrupt depletion of the limiting reactant. The inflection point, defined by \\frac{d^2pH}{dV^2} = 0, mathematically identifies this maximum slope of the titration curve, which coincides with the equivalence point in symmetric neutralization systems.','The inflection point is the point of maximum slope (d(pH)/dV) where the stoichiometric equivalence of moles is achieved.','["Neutralization Curves", "pH Titration"]','conceptual','0.98',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('79c8f13c024ba71424eb9cb2e874a4dd07779458991e7561890aea0a5041e55c','Viva Voce','Unknown Subject (CH24102)','CH24102','12','2026','Q.12(b)','Why does plotting a differential curve of delta pH divided by delta V versus average volume clarify the endpoint location much better than a standard titration plot?','\\text{Why does plotting a differential curve of delta pH divided by delta V versus average volume clarify the endpoint location much better than a standard titration plot?}','1. Conceptual Analysis: A standard titration curve plots pH versus volume. The endpoint corresponds to an inflection point, where the slope (pH/V) reaches its maximum. Identifying the exact point of maximum slope on a sigmoidal curve by eye is imprecise. 2. Mathematical Approach: The first derivative of the titration curve, delta pH/delta V, represents the slope at each interval. When plotted against the average volume, the inflection point of the original sigmoidal curve manifests as a clear, sharp peak. 3. Interpretation: The peak of the first derivative plot provides a localized, distinct coordinate for the equivalence point, significantly reducing the uncertainty associated with estimating the \'steepest part\' of a standard titration curve.','1. Let the titration curve be defined as pH = f(V). The equivalence point occurs at the inflection point, where f\'\'(V) = 0 and f\'(V) is at a maximum. 2. A standard titration plot is the graph of f(V) vs. V. Estimating the point of maximum slope by visual inspection is inherently subjective. 3. By calculating the first derivative, \\Delta pH / \\Delta V \\approx f\'(V), and plotting this against V_avg = (V_n + V_{n-1})/2, we transform an inflection point into a local maximum. 4. The peak of this curve, defined by the coordinates (V_{eq}, f\'(V_{eq})), provides a precise, unambiguous determination of the equivalence volume V_{eq} because the rate of change of the slope is zero at this point.','The differential plot converts the inflection point of a sigmoidal titration curve into a distinct, measurable peak, allowing for precise identification of the equivalence volume where the slope is at its maximum.','["Differential Titration Curves", "pH Titration"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);